        );

        let stream =
            futures_util::stream::iter(vec![Ok::<_, reqwest::Error>(bytes::Bytes::from(sse_data))]);

        let (blocks, stop, _usage) = parse_sse_stream(stream, &mut |_| {}).await.unwrap();

