                "#!/bin/bash\ncat > {}\necho '{{}}'\n",
                observe_log.display()
            ),
        )
        .unwrap();

        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            fs::set_permissions(&guard_script, fs::Permissions::from_mode(0o755)).unwrap();
            fs::set_permissions(&observe_script, fs::Permissions::from_mode(0o755)).unwrap();
