    #[test]
    fn consecutive_block_threshold_logic() {
        // Simulate consecutive blocks hitting threshold
        let mut consecutive = 0usize;
        let mut tripped = false;

        for _ in 0..3 {
            consecutive += 1;
            if consecutive >= MAX_CONSECUTIVE_BLOCKS {
