    }

    #[test]
    fn both_counters_reset_on_outer_loop() {
        // In run_turn, both are initialized to 0 (fresh per call).
        // Verify by simulating two "turns":
        let make_counters = || -> (usize, usize) { (0, 0) };

        let (c1, t1) = make_counters();
