1734→    use std::sync::Mutex;
1735→    static CWD_MUTEX: Mutex<()> = Mutex::new(());
1736→
1737→    /// Helper: run a closure with a temporary directory as cwd, then restore.
1738→    fn with_temp_cwd<F: FnOnce(&std::path::Path)>(f: F) {
1739→        let _lock = CWD_MUTEX.lock().unwrap();
1740→        let original = std::env::current_dir().unwrap();
1741→        let tmp = tempfile::tempdir().unwrap();
1742→        std::env::set_current_dir(tmp.path()).unwrap();
1743→        f(tmp.path());
1744→        std::env::set_current_dir(original).unwrap();
1745→    }
