2049→    #[tokio::test]
2050→    async fn parallel_path_null_input_blocked_skips_post_hooks() {
2051→        // Simulates the parallel dispatch loop with a batch containing one valid
2052→        // tool and one null-input tool. Verifies:
2053→        //   (a) null-input slot gets an error ToolResult
2054→        //   (b) blocked_flags[i] is set for the null-input tool
2055→        //   (c) post-dispatch is skipped for the blocked slot
2056→        let hooks = HookRunner::load("/nonexistent/hooks.toml", "/tmp");
2057→        let tool_uses: Vec<(String, String, serde_json::Value)> = vec![
2058→            (
2059→                "tu_valid".to_string(),
2060→                "Read".to_string(),
2061→                serde_json::json!({"file_path": "/dev/null"}),
2062→            ),
2063→            (
2064→                "tu_null".to_string(),
2065→                "Bash".to_string(),
2066→                serde_json::Value::Null,
2067→            ),
2068→        ];
2069→        let batch_size = tool_uses.len();
2070→        let mut slots: Vec<Option<ContentBlock>> = vec![None; batch_size];
2071→        let mut blocked_flags: Vec<bool> = vec![false; batch_size];
2072→        let mut spawn_futures: Vec<(usize, tokio::task::JoinHandle<ContentBlock>)> = Vec::new();
2073→        let mut consecutive_block_count = 0usize;
2074→        let mut total_block_count = 0usize;
2075→        let mut threshold_tripped = false;
2076→
2077→        for (i, (id, name, input)) in tool_uses.iter().enumerate() {
2078→            match run_pre_dispatch(
2079→                &hooks,
2080→                id,
2081→                name,
2082→                input,
2083→                0,
2084→                &mut consecutive_block_count,
2085→                &mut total_block_count,
2086→            )
2087→            .await
2088→            {
2089→                PreDispatchResult::Allow => {
2090→                    let id = id.clone();
2091→                    let name = name.clone();
2092→                    let input = input.clone();
2093→                    let handle = tokio::task::spawn_blocking(move || {
2094→                        dispatch_to_tool_result(id, name, input)
2095→                    });
2096→                    spawn_futures.push((i, handle));
2097→                }
2098→                PreDispatchResult::Blocked(cb) => {
2099→                    slots[i] = Some(cb);
2100→                    blocked_flags[i] = true;
2101→                }
2102→                PreDispatchResult::ThresholdTripped => {
2103→                    threshold_tripped = true;
2104→                    break;
2105→                }
2106→            }
2107→        }
2108→
2109→        join_spawned_futures(spawn_futures, &mut slots, &tool_uses).await;
2110→        assert!(!threshold_tripped, "no threshold should trip");
2111→
2112→        // Verify: slot 0 (valid Read) was dispatched and has a result
2113→        assert!(!blocked_flags[0], "valid tool should not be blocked");
2114→        assert!(slots[0].is_some(), "valid tool slot should be filled");
2115→        if let Some(ContentBlock::ToolResult { is_error, .. }) = &slots[0] {
2116→            assert!(is_error.is_none(), "Read /dev/null should succeed");
2117→        }
2118→
2119→        // Verify: slot 1 (null-input) is blocked with error ToolResult
2120→        assert!(blocked_flags[1], "null-input tool should be blocked");
2121→        if let Some(ContentBlock::ToolResult {
2122→            tool_use_id,
2123→            content,
2124→            is_error,
2125→        }) = &slots[1]
2126→        {
2127→            assert_eq!(tool_use_id, "tu_null");
2128→            assert!(content.contains("null input"));
2129→            assert_eq!(*is_error, Some(true));
2130→        } else {
2131→            panic!("expected ToolResult for null-input slot");
2132→        }
2133→
2134→        // Verify: post-dispatch loop skips blocked slots (the `continue` path)
2135→        let mut post_dispatch_count = 0;
2136→        for (i, (_, name, input)) in tool_uses.iter().enumerate() {
2137→            if blocked_flags[i] {
2138→                continue;
2139→            }
2140→            if let Some(ContentBlock::ToolResult {
2141→                ref content,
2142→                is_error,
2143→                ..
2144→            }) = slots[i]
2145→            {
2146→                let is_err = is_error.unwrap_or(false);
2147→                let _ = run_post_dispatch(&hooks, name, input, content, is_err, 0, false).await;
2148→                post_dispatch_count += 1;
2149→            }
2150→        }
2151→        // Only the valid (non-blocked) tool should get post-dispatch
2152→        assert_eq!(
2153→            post_dispatch_count, 1,
2154→            "post-dispatch should fire for valid tool only"
2155→        );
2156→    }
