2200→            // Tool 0: Read (not matched by guard) → Allow → spawned
2201→            (
2202→                "tu_0".to_string(),
2203→                "Read".to_string(),
2204→                serde_json::json!({"file_path": "/dev/null"}),
2205→            ),
2206→            // Tools 1-3: Bash (matched by guard) → Block, Block, ThresholdTripped
2207→            (
2208→                "tu_1".to_string(),
2209→                "Bash".to_string(),
2210→                serde_json::json!({"command": "echo 1"}),
2211→            ),
2212→            (
2213→                "tu_2".to_string(),
2214→                "Bash".to_string(),
2215→                serde_json::json!({"command": "echo 2"}),
2216→            ),
2217→            (
2218→                "tu_3".to_string(),
2219→                "Bash".to_string(),
2220→                serde_json::json!({"command": "echo 3"}),
