2225→        let mut blocked_flags: Vec<bool> = vec![false; batch_size];
2226→        let mut spawn_futures: Vec<(usize, tokio::task::JoinHandle<ContentBlock>)> = Vec::new();
2227→        let mut consecutive_block_count = 0usize;
2228→        let mut total_block_count = 0usize;
2229→        let mut threshold_tripped = false;
2230→        let mut threshold_reason = TurnStopReason::EndTurn;
2231→
2232→        for (i, (id, name, input)) in tool_uses.iter().enumerate() {
2233→            match run_pre_dispatch(
2234→                &hooks,
2235→                id,
2236→                name,
2237→                input,
2238→                0,
2239→                &mut consecutive_block_count,
2240→                &mut total_block_count,
2241→            )
2242→            .await
2243→            {
