2245→                    let id = id.clone();
2246→                    let name = name.clone();
2247→                    let input = input.clone();
2248→                    let handle = tokio::task::spawn_blocking(move || {
2249→                        dispatch_to_tool_result(id, name, input)
2250→                    });
2251→                    spawn_futures.push((i, handle));
2252→                }
2253→                PreDispatchResult::Blocked(cb) => {
