    #[test]
    fn recover_conversation_preserves_minimum_after_orphan_pop() {
        // Three messages: [user, assistant(tool_use only), user].
        // Without the guard, all three would be popped leaving an empty vec.
        let mut msgs = vec![
            Message {
                role: "user".to_string(),
