        let logged = fs::read_to_string(&observe_log).unwrap();
        let parsed: Value = serde_json::from_str(&logged).unwrap();
        assert_eq!(parsed["blocked"], true);
        assert_eq!(
            parsed["blocked_by"].as_str().unwrap(),
            guard_script.to_str().unwrap()
