        assert_eq!(RETRY_AFTER_CAP, 60);
    }

    #[test]
    fn permanent_error_skips_retry() {
        // Verify that classify_error returns Permanent for 400
        let e = AgentError::HttpError {
            status: 400,
            retry_after: None,
