        }

        let files: Vec<_> = (0..3)
            .map(|i| {
                (
                    format!("id_{i}"),
                    dir.join(format!("ord{i}.txt"))
                        .to_str()
                        .unwrap()
                        .to_string(),
                )
            })
            .collect();

        let handles: Vec<_> = files
            .iter()
